import { readFile } from 'node:fs/promises';
import { execSync } from 'node:child_process';

async function runTest(test) {
  if (test.type === 'file_exists') {
    await readFile(test.target, 'utf8');
    return true;
  }

  if (test.type === 'json_parseable') {
    const content = await readFile(test.target, 'utf8');
    JSON.parse(content);
    return true;
  }

  if (test.type === 'file_contains_string') {
    const content = await readFile(test.target, 'utf8');
    return content.includes(test.expected);
  }

  if (test.type === 'file_contains_export') {
    const content = await readFile(test.target, 'utf8');
    return content.includes(`export ${test.expected}`) || content.includes(`export async function ${test.expected}`) || content.includes(`export function ${test.expected}`);
  }

  if (test.type === 'file_exact_match') {
    const content = await readFile(test.target, 'utf8');
    return content === test.expected;
  }

  if (test.type === 'node_check') {
    try {
      execSync(`node --check ${JSON.stringify(test.target)}`, { stdio: 'pipe' });
      return true;
    } catch {
      return false;
    }
  }

  throw new Error(`UNSUPPORTED_TEST_TYPE:${test.type}`);
}

export async function verifyStepResult(result, acceptanceTests) {
  const failedTestIds = [];

  for (const test of acceptanceTests) {
    const passed = await runTest(test);
    if (!passed) {
      failedTestIds.push(test.test_id);
    }
  }

  return {
    status: failedTestIds.length === 0 ? 'VERIFIED' : 'FAILED_VERIFICATION',
    passed: failedTestIds.length === 0,
    failed_test_ids: failedTestIds,
    builder_result: result
  };
}

const REQUIRED_FIELDS = ['mission_id', 'blueprint_id', 'step_id', 'builder_status', 'verifier_status', 'timestamp'];

export async function recordStepOutcome(receipt) {
  for (const field of REQUIRED_FIELDS) {
    if (!(field in receipt)) {
      throw new Error(`MISSING_RECEIPT_FIELD:${field}`);
    }
  }

  return receipt;
}

const REQUIRED_FIELDS = ['mission_id', 'blueprint_id', 'step_id', 'status', 'started_at', 'finished_at'];

export async function recordStepMetrics(metrics) {
  for (const field of REQUIRED_FIELDS) {
    if (!(field in metrics)) {
      throw new Error(`MISSING_METRICS_FIELD:${field}`);
    }
  }

  return {
    ...metrics,
    duration_ms: new Date(metrics.finished_at).getTime() - new Date(metrics.started_at).getTime()
  };
}

import { appendFile, readFile, writeFile } from 'node:fs/promises';
import { resolve, sep } from 'node:path';

const SANDBOX_ROOT = resolve(process.cwd(), 'factory-v1');

function blocked(step, summary, missingInformation, evidence) {
  return {
    status: 'BLOCKED_RETURN_TO_BPB',
    mission_id: step?.mission_id || null,
    blueprint_id: step?.blueprint_id || null,
    step_id: step?.step_id || null,
    gap_type: 'ambiguous_spec',
    summary,
    attempted_action: 'execute_step',
    missing_information: missingInformation,
    evidence
  };
}

function resolveSandboxedPath(targetFile) {
  const resolved = resolve(process.cwd(), targetFile);
  if (!(resolved === SANDBOX_ROOT || resolved.startsWith(`${SANDBOX_ROOT}${sep}`))) {
    const error = new Error(`Target outside factory sandbox: ${targetFile}`);
    error.code = 'MISSION_VIOLATION';
    throw error;
  }
  return resolved;
}

export async function executeStep(step) {
  if (!step || !step.type || !step.target_file) {
    return blocked(step, 'Missing required step fields.', ['type', 'target_file'], ['Step payload missing required execution fields.']);
  }

  const targetPath = resolveSandboxedPath(step.target_file);

  if (step.type === 'write_file_exact') {
    if (typeof step.content !== 'string') {
      return blocked(step, 'write_file_exact requires string content.', ['content'], ['step.content was not provided as a string.']);
    }
    await writeFile(targetPath, step.content, 'utf8');
    return { status: 'DONE', target_file: step.target_file };
  }

  if (step.type === 'append_file_exact') {
    if (typeof step.content !== 'string') {
      return blocked(step, 'append_file_exact requires string content.', ['content'], ['step.content was not provided as a string.']);
    }
    await appendFile(targetPath, step.content, 'utf8');
    return { status: 'DONE', target_file: step.target_file };
  }

  if (step.type === 'replace_file_exact') {
    if (typeof step.find !== 'string' || typeof step.replace !== 'string') {
      return blocked(step, 'replace_file_exact requires string find and replace fields.', ['find', 'replace'], ['step.find or step.replace was not provided as a string.']);
    }
    const original = await readFile(targetPath, 'utf8');
    if (!original.includes(step.find)) {
      return blocked(step, 'replace_file_exact could not find target string.', ['find must exist in target_file'], ['Specified find string was not present in target file.']);
    }
    await writeFile(targetPath, original.split(step.find).join(step.replace), 'utf8');
    return { status: 'DONE', target_file: step.target_file };
  }

  const error = new Error(`Unsupported builder action: ${step.type}`);
  error.code = 'MISSION_VIOLATION';
  throw error;
}

import { executeStep } from '../builder/execute-step.js';
import { verifyStepResult } from '../sentry/verify-step-result.js';
import { recordStepOutcome } from '../historian/record-step-outcome.js';
import { recordStepMetrics } from '../tsos/record-step-metrics.js';

export async function runFrozenStep({ step, acceptanceTests }) {
  const startedAt = new Date().toISOString();
  const builder = await executeStep(step);
  const finishedAt = new Date().toISOString();

  const verifier = builder.status === 'BLOCKED_RETURN_TO_BPB'
    ? { status: 'SKIPPED_VERIFICATION', passed: false, failed_test_ids: [] }
    : await verifyStepResult(builder, acceptanceTests);

  const historian = await recordStepOutcome({
    mission_id: step.mission_id,
    blueprint_id: step.blueprint_id,
    step_id: step.step_id,
    builder_status: builder.status,
    verifier_status: verifier.status,
    timestamp: finishedAt
  });

  const tsos = await recordStepMetrics({
    mission_id: step.mission_id,
    blueprint_id: step.blueprint_id,
    step_id: step.step_id,
    status: verifier.status === 'FAILED_VERIFICATION' ? 'FAILED_VERIFICATION' : builder.status,
    started_at: startedAt,
    finished_at: finishedAt
  });

  return {
    status: verifier.status === 'FAILED_VERIFICATION' ? 'FAILED_VERIFICATION' : builder.status,
    builder,
    verifier,
    historian,
    tsos
  };
}

import express from 'express';
import acceptanceRegistry from '../contracts/acceptance-tests-registry.json' with { type: 'json' };
import { runFrozenStep } from '../runtime/run-frozen-step.js';

export function createFactoryExecuteStepRoutes() {
  const router = express.Router();

  router.post('/execute-step', async (req, res, next) => {
    try {
      const { step } = req.body || {};
      if (!step || !step.step_id) {
        return res.status(400).json({
          status: 'BLOCKED_RETURN_TO_BPB',
          summary: 'Request body must include a step with step_id.'
        });
      }

      const acceptanceTests = acceptanceRegistry.tests.filter((test) => test.step_id === step.step_id);
      if (acceptanceTests.length === 0) {
        return res.status(400).json({
          status: 'BLOCKED_RETURN_TO_BPB',
          summary: 'No blueprint-owned acceptance tests found for step.'
        });
      }

      const result = await runFrozenStep({ step, acceptanceTests });
      return res.json(result);
    } catch (error) {
      return next(error);
    }
  });

  return router;
}
